import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"플랫폼 기능: 핵심 명령어와 스킬 관리 | OpenSkills","description":"OpenSkills 플랫폼 기능을 학습하세요. 명령어, 설치, 나열, 업데이트, 삭제 등 핵심 작업을 마스터하고 전역과 프로젝트 관리의 차이를 이해합니다.","frontmatter":{"title":"플랫폼 기능: 핵심 명령어와 스킬 관리 | OpenSkills","sidebarTitle":"핵심 작업 마스터하기","subtitle":"플랫폼 기능: 핵심 명령어와 스킬 관리 | OpenSkills","description":"OpenSkills 플랫폼 기능을 학습하세요. 명령어, 설치, 나열, 업데이트, 삭제 등 핵심 작업을 마스터하고 전역과 프로젝트 관리의 차이를 이해합니다.","order":2},"headers":[],"relativePath":"ko/numman-ali/openskills/platforms/index.md","filePath":"ko/numman-ali/openskills/platforms/index.md"}'),s={name:"ko/numman-ali/openskills/platforms/index.md"};function i(o,a,d,n,h,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="플랫폼-기능" tabindex="-1">플랫폼 기능 <a class="header-anchor" href="#플랫폼-기능" aria-label="Permalink to &quot;플랫폼 기능&quot;">​</a></h1><p>이 장에서는 OpenSkills CLI의 핵심 명령어와 스킬 관리 기능을 심도 있게 다루어, &quot;사용할 수 있음&quot;에서 &quot;마스터&quot;로 발전하도록 도와드립니다.</p><h2 id="사전-요구-사항" tabindex="-1">사전 요구 사항 <a class="header-anchor" href="#사전-요구-사항" aria-label="Permalink to &quot;사전 요구 사항&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작 전 확인</p><p>이 장을 학습하기 전에 <a href="./../start/">빠른 시작</a> 장을 완료했는지 확인하세요. 특히:</p><ul><li><a href="./../start/installation/">OpenSkills 설치</a>: OpenSkills CLI가 성공적으로 설치되었는지 확인</li><li><a href="./../start/first-skill/">첫 번째 스킬 설치</a>: 기본적인 스킬 설치 프로세스 이해</li></ul></div><h2 id="이-장-내용" tabindex="-1">이 장 내용 <a class="header-anchor" href="#이-장-내용" aria-label="Permalink to &quot;이 장 내용&quot;">​</a></h2><p>이 장은 OpenSkills의 모든 핵심 기능을 다루는 6가지 주제를 포함합니다:</p><h3 id="명령어-상세-설명" tabindex="-1"><a href="./cli-commands/">명령어 상세 설명</a> <a class="header-anchor" href="#명령어-상세-설명" aria-label="Permalink to &quot;[명령어 상세 설명](./cli-commands/)&quot;">​</a></h3><p>7개 명령어, 파라미터 및 플래그를 완전히 소개하고 명령어 요약 표를 제공합니다. 명령어 사용법을 빠르게 찾아야 하는 사용자에게 적합합니다.</p><h3 id="설치-소스-상세-설명" tabindex="-1"><a href="./install-sources/">설치 소스 상세 설명</a> <a class="header-anchor" href="#설치-소스-상세-설명" aria-label="Permalink to &quot;[설치 소스 상세 설명](./install-sources/)&quot;">​</a></h3><p>GitHub 저장소, 로컬 경로, 개인 Git 저장소의 세 가지 설치 소스를 자세히 설명합니다. 각 방식의 사용 시나리오, 명령어 형식 및 주의사항을 다룹니다.</p><h3 id="전역-설치-vs-프로젝트-로컬-설치" tabindex="-1"><a href="./global-vs-project/">전역 설치 vs 프로젝트 로컬 설치</a> <a class="header-anchor" href="#전역-설치-vs-프로젝트-로컬-설치" aria-label="Permalink to &quot;[전역 설치 vs 프로젝트 로컬 설치](./global-vs-project/)&quot;">​</a></h3><p><code>--global</code>과 기본(프로젝트 로컬) 설치의 차이를 설명하여, 적절한 설치 위치를 선택하고 스킬 검색 우선순위 규칙을 이해할 수 있도록 돕습니다.</p><h3 id="설치된-스킬-나열" tabindex="-1"><a href="./list-skills/">설치된 스킬 나열</a> <a class="header-anchor" href="#설치된-스킬-나열" aria-label="Permalink to &quot;[설치된 스킬 나열](./list-skills/)&quot;">​</a></h3><p><code>list</code> 명령어를 사용하여 설치된 스킬을 보는 방법을 알려드리고 <code>(project)</code> 및 <code>(global)</code> 위치 태그의 의미를 이해합니다.</p><h3 id="스킬-업데이트" tabindex="-1"><a href="./update-skills/">스킬 업데이트</a> <a class="header-anchor" href="#스킬-업데이트" aria-label="Permalink to &quot;[스킬 업데이트](./update-skills/)&quot;">​</a></h3><p><code>update</code> 명령어를 사용하여 설치된 스킬을 새로 고치는 방법을 안내합니다. 모든 스킬 업데이트와 지정된 스킬 업데이트를 지원하여 스킬을 원본 저장소와 동기화합니다.</p><h3 id="스킬-삭제" tabindex="-1"><a href="./remove-skills/">스킬 삭제</a> <a class="header-anchor" href="#스킬-삭제" aria-label="Permalink to &quot;[스킬 삭제](./remove-skills/)&quot;">​</a></h3><p>대화형 <code>manage</code> 명령어와 스크립트 방식 <code>remove</code> 명령어의 두 가지 삭제 방법을 소개하여 스킬 라이브러리를 효율적으로 관리할 수 있도록 돕습니다.</p><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>요구사항에 따라 적절한 학습 경로를 선택하세요:</p><h3 id="경로-a-체계적-학습-초보자-추천" tabindex="-1">경로 A: 체계적 학습(초보자 추천) <a class="header-anchor" href="#경로-a-체계적-학습-초보자-추천" aria-label="Permalink to &quot;경로 A: 체계적 학습(초보자 추천)&quot;">​</a></h3><p>순서대로 모든 내용을 학습하여 완전한 지식 체계를 구축하세요:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>명령어 상세 설명 → 설치 소스 → 전역 vs 프로젝트 → 스킬 나열 → 스킬 업데이트 → 스킬 삭제</span></span></code></pre></div><h3 id="경로-b-필요에-따른-참조" tabindex="-1">경로 B: 필요에 따른 참조 <a class="header-anchor" href="#경로-b-필요에-따른-참조" aria-label="Permalink to &quot;경로 B: 필요에 따른 참조&quot;">​</a></h3><p>현재 작업에 따라 바로 이동하세요:</p><table tabindex="0"><thead><tr><th>하고 싶은 것</th><th>이 문서 읽기</th></tr></thead><tbody><tr><td>특정 명령어 사용법 찾기</td><td><a href="./cli-commands/">명령어 상세 설명</a></td></tr><tr><td>개인 저장소에서 스킬 설치</td><td><a href="./install-sources/">설치 소스 상세 설명</a></td></tr><tr><td>전역 또는 프로젝트 설치 결정</td><td><a href="./global-vs-project/">전역 vs 프로젝트</a></td></tr><tr><td>설치된 스킬 확인</td><td><a href="./list-skills/">설치된 스킬 나열</a></td></tr><tr><td>스킬을 최신 버전으로 업데이트</td><td><a href="./update-skills/">스킬 업데이트</a></td></tr><tr><td>사용하지 않는 스킬 정리</td><td><a href="./remove-skills/">스킬 삭제</a></td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후에는 OpenSkills의 일상 사용 스킬을 마스터했습니다. 다음으로 다음을 계속할 수 있습니다:</p><ul><li><strong><a href="./../advanced/">고급 기능</a></strong>: Universal 모드, 사용자 정의 출력 경로, 심볼릭 링크, 사용자 정의 스킬 만들기 등 고급 기능 학습</li><li><strong><a href="./../faq/">자주 묻는 질문</a></strong>: 문제 발생 시 FAQ 및 문제 해결 가이드 참조</li></ul>',29)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
